#include<bits/stdc++.h>
using namespace std;
int n,sum1[2000010],sum2[2000010],tot,kind[200010],k[200010],flag[200010],cnt;
char op[101];
int lowbit(int x)
{
    return x&-x;
}
void update(int s[],int x,int v)
{
    x+=1000002;
    for(int i=x;i<=2000005;i+=lowbit(i))
    {
        s[i]+=v;
    }
}
int query(int s[],int x)
{
    x+=1000002;
    int ans=0;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        ans+=s[i];
    }
    return ans;
}
int main()
{
    int n;
    scanf("%d",&n);
    while(n--)
    {
        scanf("%s",op);
        if(op[0]=='A')
        {
            int x,y,z;
            scanf("%d%d%d",&x,&y,&z);
            if(x==0)
            {
                if(y>z)
                {
                    cnt++;
                    kind[++tot]=3;
                }
                else
                {
                    kind[++tot]=0;
                }
                continue;
            }
            if(x>0)
            {
                k[++tot]=floor((z*1.0-y)/x);
                kind[tot]=1;
                if(k[tot]>1e6)
                {
                    kind[tot]=0;
                    continue;
                }
                if(k[tot]<-1e6)
                {
                    kind[tot]=3;
                    cnt++;
                    continue;
                }
                update(sum1,k[tot],1);
            }
            else
            {
                k[++tot]=ceil((z*1.0-y)/x);
                kind[tot]=2;
                if(k[tot]<-1e6)
                {
                    kind[tot]=0;
                    continue;
                }
                if(k[tot]>1e6)
                {
                    kind[tot]=3;
                    cnt++;
                    continue;
                }
                update(sum2,k[tot],1);
            }
        }
        else if(op[0]=='Q')
        {
            int x;
            scanf("%d",&x);
            printf("%d\n",query(sum1,x-1)+(query(sum2,1000000)-query(sum2,x))+cnt);
        }
        else
        {
            int x;
            scanf("%d",&x);
            if(flag[x])
            {
                continue;
            }
            flag[x]=1;
            if(kind[x]==1)
            {
                update(sum1,k[x],-1);
            }
            else if(kind[x]==2)
            {
                update(sum2,k[x],-1);
            }
            else if(kind[x]==3)
            {
                cnt--;
            }
        }
    }
    return 0;
}
